```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create a hexi::deserializer object from the buffer
    hexi::deserializer deserializer(buffer);

    NetworkPacket packet;

    // Read packet_id using deserializer's operator>>
    deserializer >> packet.packet_id;

    // Read username using deserializer's operator>> with hexi::prefixed<std::string>
    deserializer >> hexi::prefixed(packet.username);

    // Read scores: first read the count, then use hexi::read_container
    uint32_t score_count;
    deserializer >> score_count;
    hexi::read_container(packet.scores, score_count);

    // Read metadata using deserializer's operator>> with hexi::null_terminated<std::string>
    deserializer >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    deserializer.skip(buffer.size() - deserializer.total_read());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create a hexi::deserializer object from the buffer
    hexi::deserializer deserializer(buffer);

    PacketInfo info;

    // Use span() to get a zero-copy view of the packet_id (first 4 bytes)
    auto id_span = deserializer.span<uint32_t>(1);
    info.packet_id = *id_span.data();

    // Read username using prefixed adaptor to get a string_view
    deserializer >> hexi::prefixed(info.username);

    // Skip the scores vector without reading its elements
    uint32_t score_count;
    deserializer >> score_count;
    deserializer.skip(score_count * sizeof(uint32_t));

    return info;
}
```

