    // Serialize packet_id as a fixed-size integer (no varint needed)
    writer << packet.packet_id;

    // Serialize tags using prefixed_varint adaptor for compact encoding
    writer << hexi::prefixed_varint(packet.tags);

    // Serialize data using prefixed_varint adaptor for compact encoding
    writer << hexi::prefixed_varint(packet.data);

    return buffer;
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet;

    // Create a buffer adaptor for the input span
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);

    // Create a binary stream reader using the adaptor
    hexi::binary_stream_reader reader(adaptor);

    // Deserialize packet_id as a fixed-size integer
    reader >> packet.packet_id;

    // Deserialize tags using prefixed_varint adaptor
    reader >> hexi::prefixed_varint(packet.tags);

    // Deserialize data using prefixed_varint adaptor
    reader >> hexi::prefixed_varint(packet.data);

    return packet;
}

