```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to hold the written data
    std::vector<std::uint8_t> buffer;

    // Create buffer write adaptor
    hexi::pmc::buffer_write_adaptor<std::vector<std::uint8_t>> adaptor(buffer);

    // Write each chunk with size tracking
    for (const auto& chunk : chunks) {
        // Check available space before each write
        std::size_t available_space = adaptor.free();

        // If chunk is larger than available space, split it
        std::size_t remaining = chunk.size();
        std::size_t offset = 0;

        while (remaining > 0) {
            // Calculate how much we can write this iteration
            std::size_t write_size = std::min(available_space, remaining);

            // Write portion of the chunk
            adaptor.write(chunk.data() + offset, write_size);

            // Update remaining and offset
            remaining -= write_size;
            offset += write_size;

            // Update available space after write
            available_space = adaptor.free();
        }
    }

    // Return the final buffer size
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create buffer read adaptor
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Accumulator for read data
    std::vector<uint8_t> result;

    // Read until buffer is empty
    while (adaptor.size() > 0) {
        // Determine read size (min of chunk_size and remaining data)
        std::size_t read_size = std::min(adaptor.size(), chunk_size);

        // Create temporary buffer for reading
        std::vector<uint8_t> temp_buffer(read_size);

        // Read data into temporary buffer
        adaptor.read(temp_buffer.data(), read_size);

        // Append to result
        result.insert(result.end(), temp_buffer.begin(), temp_buffer.end());
    }

    return result;
}
